import Foundation

/// Controls how microphone and system audio are combined into the output WAV file.
public enum MixingStrategy: Sendable, Codable {
    /// Mic is mixed into both stereo channels alongside system audio.
    /// - Left:  mic + system_L
    /// - Right: mic + system_R
    /// This is the default and matches the original AudioCaptureKit behavior.
    case blended

    /// Mic and system audio occupy separate stereo channels with no blending.
    /// - Left (Ch 1):  mic only (mono mic signal)
    /// - Right (Ch 2): system audio, mono-folded as (system_L + system_R) / 2
    case separated

    /// Reserved for future 3-channel multi-mic configurations.
    /// Currently behaves identically to ``separated``.
    case multichannel
}

import Foundation

/// Configuration for an audio capture session.
public struct CaptureConfiguration: Sendable {
    /// Audio sample rate in Hz. Default is 48000.
    public let sampleRate: Double

    /// Bit depth for audio samples. Default is 16.
    public let bitDepth: Int

    /// Number of audio channels. Default is 2 (stereo).
    public let channels: Int

    /// Optional encryptor for encrypting audio data at rest.
    public let encryptor: (any CaptureEncryptor)?

    /// Directory where recorded files will be stored.
    public let outputDirectory: URL

    /// Optional maximum recording duration in seconds.
    public let maxDuration: TimeInterval?

    /// Optional specific microphone device ID to use instead of the system default.
    public let micDeviceID: String?

    /// Whether to capture microphone audio. Default is true.
    public let enableMicCapture: Bool

    /// Whether to capture system audio. Default is true.
    public let enableSystemCapture: Bool

    /// Determines how mic and system audio are combined into the output WAV.
    /// Default is ``MixingStrategy/blended`` to preserve existing behavior.
    public let mixingStrategy: MixingStrategy

    /// When true, writes raw PCM sidecar files alongside the WAV:
    /// - `{name}_mic.pcm`    — mono mic, signed 16-bit LE, no header
    /// - `{name}_system.pcm` — interleaved stereo system audio, signed 16-bit LE, no header
    /// Default: false.
    public let exportRawPCM: Bool

    public init(
        sampleRate: Double = 48000,
        bitDepth: Int = 16,
        channels: Int = 2,
        encryptor: (any CaptureEncryptor)? = nil,
        outputDirectory: URL,
        maxDuration: TimeInterval? = nil,
        micDeviceID: String? = nil,
        enableMicCapture: Bool = true,
        enableSystemCapture: Bool = true,
        mixingStrategy: MixingStrategy = .blended,
        exportRawPCM: Bool = false
    ) {
        self.sampleRate = sampleRate
        self.bitDepth = bitDepth
        self.channels = channels
        self.encryptor = encryptor
        self.outputDirectory = outputDirectory
        self.maxDuration = maxDuration
        self.micDeviceID = micDeviceID
        self.enableMicCapture = enableMicCapture
        self.enableSystemCapture = enableSystemCapture
        self.mixingStrategy = mixingStrategy
        self.exportRawPCM = exportRawPCM
    }
}

import Foundation

/// The result of a completed recording session.
public struct RecordingResult: Sendable, Equatable {
    /// URL of the recorded audio file on disk.
    public let fileURL: URL

    /// Total duration of the recording in seconds.
    public let duration: TimeInterval

    /// Associated metadata for the recording.
    public let metadata: RecordingMetadata

    /// SHA-256 checksum of the recorded file.
    public let checksum: String

    /// URLs of raw PCM sidecar files. [0] = mic.pcm (mono), [1] = system.pcm (stereo interleaved).
    /// Empty unless exportRawPCM was enabled in configuration.
    public let rawPCMFileURLs: [URL]

    public init(
        fileURL: URL,
        duration: TimeInterval,
        metadata: RecordingMetadata,
        checksum: String,
        rawPCMFileURLs: [URL] = []
    ) {
        self.fileURL = fileURL
        self.duration = duration
        self.metadata = metadata
        self.checksum = checksum
        self.rawPCMFileURLs = rawPCMFileURLs
    }
}

import Foundation

/// Metadata associated with a completed recording.
///
/// This struct is persisted alongside the audio file and contains
/// all information needed to identify, verify, and decrypt the recording.
public struct RecordingMetadata: Codable, Sendable, Equatable {
    /// Unique identifier for this recording.
    public let id: UUID

    /// Duration of the recording in seconds.
    public let duration: TimeInterval

    /// URL of the recording file on disk.
    public let fileURL: URL

    /// SHA-256 checksum of the audio file for integrity verification.
    public let checksum: String

    /// Whether the recording is encrypted.
    public let isEncrypted: Bool

    /// Timestamp when the recording was created.
    public let createdAt: Date

    /// Audio tracks in this recording.
    public let tracks: [AudioTrack]

    /// The encryption algorithm used (e.g., "AES-256-GCM"), if encrypted.
    public let encryptionAlgorithm: String?

    /// Identifier for the encryption key used, if encrypted.
    public let encryptionKeyId: String?

    /// The WAV channel layout used for this recording.
    public let channelLayout: ChannelLayout

    private enum CodingKeys: String, CodingKey {
        case id, duration, fileURL, checksum, isEncrypted, createdAt, tracks,
             encryptionAlgorithm, encryptionKeyId, channelLayout
    }

    public init(
        id: UUID = UUID(),
        duration: TimeInterval,
        fileURL: URL,
        checksum: String,
        isEncrypted: Bool,
        createdAt: Date = Date(),
        tracks: [AudioTrack],
        encryptionAlgorithm: String? = nil,
        encryptionKeyId: String? = nil,
        channelLayout: ChannelLayout = .blended
    ) {
        self.id = id
        self.duration = duration
        self.fileURL = fileURL
        self.checksum = checksum
        self.isEncrypted = isEncrypted
        self.createdAt = createdAt
        self.tracks = tracks
        self.encryptionAlgorithm = encryptionAlgorithm
        self.encryptionKeyId = encryptionKeyId
        self.channelLayout = channelLayout
    }

    public init(from decoder: any Decoder) throws {
        let container = try decoder.container(keyedBy: CodingKeys.self)
        id = try container.decode(UUID.self, forKey: .id)
        duration = try container.decode(TimeInterval.self, forKey: .duration)
        fileURL = try container.decode(URL.self, forKey: .fileURL)
        checksum = try container.decode(String.self, forKey: .checksum)
        isEncrypted = try container.decode(Bool.self, forKey: .isEncrypted)
        createdAt = try container.decode(Date.self, forKey: .createdAt)
        tracks = try container.decode([AudioTrack].self, forKey: .tracks)
        encryptionAlgorithm = try container.decodeIfPresent(String.self, forKey: .encryptionAlgorithm)
        encryptionKeyId = try container.decodeIfPresent(String.self, forKey: .encryptionKeyId)
        channelLayout = (try? container.decodeIfPresent(ChannelLayout.self, forKey: .channelLayout)) ?? .blended
    }
}

import Foundation

/// Delegate protocol for receiving capture session events.
///
/// All delegate methods are called on an unspecified queue.
/// Implementations should dispatch to the main actor if UI updates are needed.
public protocol AudioCaptureDelegate: AnyObject, Sendable {
    /// Called when the capture session state changes.
    /// - Parameters:
    ///   - session: The capture session that changed state.
    ///   - state: The new state.
    func captureSession(_ session: any AudioCaptureSession, didChangeState state: CaptureState)

    /// Called periodically with updated audio level metering.
    /// - Parameters:
    ///   - session: The capture session providing levels.
    ///   - levels: The current audio levels.
    func captureSession(_ session: any AudioCaptureSession, didUpdateLevels levels: AudioLevels)

    /// Called when the capture session encounters a non-fatal error.
    /// - Parameters:
    ///   - session: The capture session that encountered the error.
    ///   - error: The error that occurred.
    func captureSession(_ session: any AudioCaptureSession, didEncounterError error: CaptureError)

    /// Called when the capture session finishes recording.
    /// - Parameters:
    ///   - session: The capture session that finished.
    ///   - result: The recording result containing file URL, duration, and metadata.
    func captureSession(_ session: any AudioCaptureSession, didFinishCapture result: RecordingResult)

    /// Called on each processing cycle (~100 ms intervals) with raw per-channel
    /// audio samples, before mixing and file writing.
    ///
    /// Called on an unspecified background queue. Implementations must be
    /// non-blocking; dispatch heavy work asynchronously.
    func captureSession(
        _ session: any AudioCaptureSession,
        didProduceChannelBuffers buffers: ChannelBuffers
    )
}

extension AudioCaptureDelegate {
    public func captureSession(
        _: any AudioCaptureSession,
        didProduceChannelBuffers _: ChannelBuffers
    ) {}
}

